Map of unmatched facilities in FY25



Code
map_data &lt;- peak_fy25 |&gt;
  filter(peak_pop &gt; 0, !is.na(latitude), !is.na(longitude))

map_sf &lt;- st_as_sf(map_data, coords = c("longitude", "latitude"), crs = 4326)

type_colors &lt;- c(
  "Dedicated"     = "#e41a1c",
  "Non-Dedicated" = "#377eb8",
  "Federal"       = "#4daf4a",
  "Hold/Staging"  = "#ff7f00",
  "Family/Youth"  = "#984ea3",
  "Medical"       = "#a65628",
  "Other/Unknown" = "#999999",
  "Unclassified"  = "#333333"
)

map_sf$type_grouped &lt;- factor(map_sf$type_grouped, levels = names(type_colors))
present_levels &lt;- levels(droplevels(map_sf$type_grouped))
pal &lt;- colorFactor(palette = type_colors[present_levels], domain = present_levels)

# sqrt scale for area-proportional circle sizing
radii &lt;- scales::rescale(sqrt(map_sf$peak_pop), to = c(3, 20))

map_sf$peak_class &lt;- factor(map_sf$peak_class, levels = c("Peak &lt; 2", "Peak ≥ 2"))

leaflet(map_sf) |&gt;
  fitBounds(lng1 = -125, lat1 = 17.5, lng2 = -65, lat2 = 49.5) |&gt;
  addProviderTiles("CartoDB.Positron") |&gt;

  # Layer 1: Peak &lt; 2  (small solid points, no border)
  addCircleMarkers(
    data        = subset(map_sf, peak_class == "Peak &lt; 2"),
    radius      = 3,                # small fixed dot
    stroke      = FALSE,            # &lt;- no outer border
    fillColor   = ~pal(type_grouped),
    fillOpacity = 1,                # solid
    label       = ~paste0(detention_facility, " (", state, ": peak ", peak_pop, ")"),
    popup       = ~paste0(
      "&lt;b&gt;", detention_facility, "&lt;/b&gt;&lt;br&gt;",
      state, " | ", type_grouped, "&lt;br&gt;",
      "Peak: ", peak_pop, " (", peak_date, ")&lt;br&gt;",
      "Mean ADP: ", mean_pop
    ),
    group = "Peak &lt; 2"
  ) |&gt;

  # Layer 2: Peak ≥ 2
  addCircleMarkers(
    data        = subset(map_sf, peak_class == "Peak ≥ 2"),
    radius      = radii[map_sf$peak_class == "Peak ≥ 2"],
    color       = "black",
    weight      = 1,
    fillColor   = ~pal(type_grouped),
    fillOpacity = 0.7,
    label       = ~paste0(detention_facility, " (", state, ": peak ", peak_pop, ")"),
    popup       = ~paste0(
      "&lt;b&gt;", detention_facility, "&lt;/b&gt;&lt;br&gt;",
      state, " | ", type_grouped, "&lt;br&gt;",
      "Peak: ", peak_pop, " (", peak_date, ")&lt;br&gt;",
      "Mean ADP: ", mean_pop
    ),
    group = "Peak ≥ 2"
  ) |&gt;

  # Keep your facility-type legend
  addLegend(
    pal = pal, values = ~type_grouped,
    title = "Facility type", position = "bottomright"
  ) |&gt;

  # Add the layer toggle
  addLayersControl(
    overlayGroups = c("Peak &lt; 2", "Peak ≥ 2"),
    options = layersControlOptions(collapsed = FALSE)
  ) |&gt;
  addSearchFeatures(
    targetGroups = c("Peak &lt; 2", "Peak ≥ 2"),
    options = searchFeaturesOptions(
      zoom = 9,
      openPopup = TRUE,
      position = "topleft",
      hideMarkerOnCollapse = TRUE
    )) |&gt;
  addControl(
    position = "bottomright",
    html = htmltools::tags$style(htmltools::HTML("
      /* Force legend text left in Quarto/Bootstrap contexts */
      .leaflet-container .leaflet-control {
        text-align: left !important;
      }
      .leaflet-container .leaflet-control .legend {
        text-align: left !important;
      }

      /* Make the color swatch and label behave like a left-aligned row */
      .leaflet-container .leaflet-control .legend i {
        display: inline-block !important;
        width: 14px !important;
        height: 14px !important;
        margin: 0 8px 0 0 !important;
        vertical-align: middle !important;
      }
      .leaflet-container .leaflet-control .legend span {
        display: inline !important;
        vertical-align: middle !important;
      }
    ")))








